  cloud "Amazon API Gateway" as apigw
}

package "Security Layer" {
  cloud "Amazon Cognito" as cognito
  cloud "AWS IAM" as iam
}

package "Application Logic Layer" {
  node "AWS Lambda" as lambda {
    component "Match Data API" as match_api
    component "Prediction API" as prediction_api
    component "Chatbot Conversation Handler" as chatbot_handler
    component "Screening Recommendation Handler" as screening_handler
    component "Reminder Request Handler" as reminder_handler
    component "Reminder Processor" as reminder_processor
  }
}

package "Data & Search Layer" {
  database "DynamoDB (Match Data Store)" as ddb
  cloud "Elasticsearch (Search Index)" as es
  component "Search Indexing Sync" as indexing_sync
}

package "Machine Learning Layer" {
  cloud "Amazon SageMaker" as sagemaker
  component "Prediction Service Integration" as prediction_integration
}

package "Messaging & Notifications Layer" {
  cloud "Amazon SQS (Notification Queue)" as sqs
  cloud "Amazon SNS (Notification Service)" as sns
}

package "Streaming Layer" {
  node "Amazon EC2" as ec2 {
    component "Live Score Streaming Cluster (Kafka)" as kafka
    interface "Apache Avro Schemas" as avro
    component "Live Score Update Processor" as live_update_ec2
  }
}

