match_api --> ddb
match_api --> es
chatbot_handler --> ddb
chatbot_handler --> es

' Data & Search sync
indexing_sync --> ddb
indexing_sync --> es

' Application Logic to ML
prediction_api --> prediction_integration
prediction_integration --> sagemaker

' Messaging & Notifications
reminder_handler --> sqs
sqs --> reminder_processor
reminder_processor --> sns

' Streaming dependencies
kafka --> live_update_ec2
kafka -- avro
live_update_ec2 -- avro
live_update_ec2 --> ddb
live_update_ec2 --> es

@enduml

