skinparam componentStyle rectangle
left to right direction

skinparam defaultFontName Arial
skinparam shadowing false
skinparam ArrowColor #111111
skinparam ArrowThickness 1.5
skinparam package {
    BorderColor #111111
    BorderThickness 1
}
skinparam rectangle {
    BackgroundColor #FFFFFF
    BorderColor #111111
    BorderThickness 1
}
skinparam database {
    BackgroundColor #FFFFFF
    BorderColor #111111
    BorderThickness 1
}

package "High level architecture" as SystemBoundary {
    rectangle "user" as User

    package "Frontend" as Frontend {
        rectangle "React" as React
        rectangle "Docker\nfrontend container" as FrontendDocker
    }

    package "Backend" as Backend {
        rectangle "FastAPI" as FastAPI
        rectangle "Genius API\nintegration" as GeniusApi
        rectangle "Docker\nbackend container" as BackendDocker
    }

    package "Analytics and storage" as AnalyticsStorage {
        database "Elasticsearch" as Elasticsearch
        rectangle "Docker\nelasticsearch container" as ElasticsearchDocker

        rectangle "Kibana" as Kibana
        rectangle "Docker\nkibana container" as KibanaDocker
    }

    rectangle "Developer/Admin" as DeveloperAdmin
}

User --> React : searches for /\nprovides a song
React --> FastAPI

FastAPI --> GeniusApi : search missing songs
FastAPI --> Elasticsearch : store / retrieve\nsong moods

Kibana <--> Elasticsearch : inspect stored data
DeveloperAdmin --> Kibana

FrontendDocker ..> React
BackendDocker ..> FastAPI
ElasticsearchDocker ..> Elasticsearch
KibanaDocker ..> Kibana
@enduml

samples.pred_source:
@startuml
title Nobel Prize Laureates Autocomplete System - Component/Deployment Diagram

skinparam componentStyle rectangle

' === Deployment Nodes ===
node "Web Browser" {
  [Frontend Input Handler]
}

cloud "Heroku" {
  node "Node.js Runtime" {
    package "Routing Layer" {
      [HTTP Router]
    }

    package "Handler Module" {
      [Request Handler]
    }

    [Autocomplete Algorithm]
    [NotFound Handler]
    [Content-Type Mapper]
  }

  package "Data Access Layer" {
    [Laureate Data Source]
  }
}

database "File System" {
  [Public Assets Directory]
  [Laureate Data Files]
}

' === Component Dependencies ===
[Frontend Input Handler] --> [HTTP Router] : Initiates search requests
[HTTP Router] --> [Autocomplete Algorithm] : Routes search requests
[HTTP Router] --> [Request Handler] : Routes home requests
[HTTP Router] --> [NotFound Handler] : Routes unmatched URLs
[Autocomplete Algorithm] --> [Laureate Data Source] : Reads laureate data
[Request Handler] --> [Laureate Data Source] : Gets data for home page
[NotFound Handler] --> [Laureate Data Source] : Gets data for error page
[Request Handler] --> [Public Assets Directory] : Serves static files
[Request Handler] --> [Content-Type Mapper] : Determines MIME types
[Content-Type Mapper] --> [Public Assets Directory] : Maps extensions to types
[Laureate Data Source] --> [Laureate Data Files] : Loads JSON data

@enduml

samples.gt_source:
@startuml
!theme plain
skinparam defaultTextAlignment center

skinparam package {
    BorderThickness 1.5
}

package "Annotation Models" as AM #F8F0FA {
    rectangle "Entity Model - ChatGPT/\nLLM" as entity
    rectangle "Paragraph Model - Google\nBERT" as para
}

package "Infrastructure Layer" as Infra #EEF1F3 {
    rectangle "Tencent Cloud Server" as tencent
    rectangle "Docker Containerization" as docker
    rectangle "RabbitMQ Message Queue" as rabbitmq
}

package "Application Layer-Ant\nDesign / Vue.js" as App #FFA6FF {
    rectangle "Preset Sharing" as preset
    rectangle "Text Annotation" as annotation
    rectangle "Intelligent Mining" as mining
}

package "Gateway Layer" as Gateway #FFF5D6 {
    rectangle "Nginx Gateway" as nginx
}

package "Business Service Layer-\nSpring Boot" as Biz #E6F3FA {
    rectangle "Management Service" as mgmt
    rectangle "Annotation Service" as ann_svc
    rectangle "Mining Service" as mine_svc
}

package "Data Storage Layer" as Storage #EAF3EA {
    rectangle "MinIO Object Storage" as minio
    rectangle "MySQL Structured\nDatabase" as mysql
    rectangle "Redis Cache" as redis
}


App --> Gateway
Gateway --> Biz
Biz --> Storage


AM ...> App : Supports
AM ...> Gateway : Supports
AM ...> Biz : Supports

Infra ...> App : Supports
Infra ...> Gateway : Supports
Infra ...> Biz : Supports
Infra ...> Storage : Supports


@enduml
